/*
 * TCP Socket Server - C Implementation
 * Demonstrates TCP/IP Protocol Stack at system level
 * 
 * Network Layers Demonstrated:
 * - Application Layer: Server logic
 * - Transport Layer: TCP (SOCK_STREAM)
 * - Internet Layer: IPv4 (AF_INET)
 * - Network Interface: Ethernet
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>
#include <netinet/in.h>
#include <sys/socket.h>
#include <pthread.h>

#define PORT 8080
#define BUFFER_SIZE 1024
#define MAX_CLIENTS 5

/* Structure for client information */
struct ClientInfo {
    int client_socket;
    struct sockaddr_in client_addr;
};

/* Handle client connection */
void *handle_client(void *arg) {
    struct ClientInfo *client = (struct ClientInfo *)arg;
    char buffer[BUFFER_SIZE];

    printf("New client connected from %s:%d\n",
           inet_ntoa(client->client_addr.sin_addr),
           ntohs(client->client_addr.sin_port));

    /* Receive data from client */
    memset(buffer, 0, BUFFER_SIZE);
    ssize_t bytes_received = recv(client->client_socket, buffer, BUFFER_SIZE - 1, 0);

    if (bytes_received > 0) {
        buffer[bytes_received] = '\0';
        printf("Received from client: %s\n", buffer);

        /* Send response - TCP ensures reliable delivery */
        char response[BUFFER_SIZE];
        snprintf(response, BUFFER_SIZE, 
                 "Server ACK: Received %ld bytes - '%s'", 
                 bytes_received, buffer);

        send(client->client_socket, response, strlen(response), 0);
        printf("Response sent to client\n");
    }

    /* Close client socket - TCP connection termination */
    close(client->client_socket);
    free(client);

    return NULL;
}

int main() {
    int server_socket, client_socket;
    struct sockaddr_in server_addr, client_addr;
    socklen_t client_len;
    pthread_t thread_id;

    /* Step 1: Create socket - TCP/IP Protocol Stack
     * AF_INET: IPv4 address family
     * SOCK_STREAM: TCP (reliable, connection-oriented)
     * Use SOCK_DGRAM for UDP (connectionless) */
    server_socket = socket(AF_INET, SOCK_STREAM, 0);
    if (server_socket < 0) {
        perror("Socket creation failed");
        exit(EXIT_FAILURE);
    }
    printf("Socket created successfully\n");

    /* Allow port reuse */
    int opt = 1;
    if (setsockopt(server_socket, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt)) < 0) {
        perror("Setsockopt failed");
        exit(EXIT_FAILURE);
    }

    /* Step 2: Bind socket to port
     * Internet Layer: IP addressing */
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;          // IPv4
    server_addr.sin_addr.s_addr = INADDR_ANY;   // Any interface
    server_addr.sin_port = htons(PORT);         // Port in network byte order

    if (bind(server_socket, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("Bind failed");
        close(server_socket);
        exit(EXIT_FAILURE);
    }
    printf("Bound to port %d\n", PORT);

    /* Step 3: Listen for connections
     * TCP: Connection queue setup */
    if (listen(server_socket, MAX_CLIENTS) < 0) {
        perror("Listen failed");
        close(server_socket);
        exit(EXIT_FAILURE);
    }
    printf("Server listening on port %d...\n", PORT);

    /* Step 4: Accept connections in loop
     * TCP: Three-way handshake completion */
    while (1) {
        client_len = sizeof(client_addr);
        client_socket = accept(server_socket, 
                               (struct sockaddr *)&client_addr, 
                               &client_len);

        if (client_socket < 0) {
            perror("Accept failed");
            continue;
        }

        /* Create thread to handle client */
        struct ClientInfo *client_info = malloc(sizeof(struct ClientInfo));
        client_info->client_socket = client_socket;
        client_info->client_addr = client_addr;

        pthread_create(&thread_id, NULL, handle_client, client_info);
        pthread_detach(thread_id);
    }

    close(server_socket);
    return 0;
}

/*
 * TCP/IP Protocol Stack Layers:
 * +---------------------------+
 * | Application Layer         | <- Server logic, HTTP, FTP
 * +---------------------------+
 * | Transport Layer (TCP)    | <- SOCK_STREAM, ports, reliability
 * +---------------------------+
 * | Internet Layer (IP)     | <- Addressing, routing
 * +---------------------------+
 * | Network Interface       | <- Ethernet, WiFi
 * +---------------------------+
 * 
 * Key TCP Features Demonstrated:
 * - Socket creation (socket())
 * - Address binding (bind())
 * - Connection listening (listen())
 * - Connection acceptance (accept())
 * - Reliable data transfer (send(), recv())
 * - Connection termination (close())
 */
